-- Frozen Room v15 schema. This fixture must remain independent from YukineSchema production code.
CREATE TABLE tracks (id INTEGER PRIMARY KEY,title TEXT NOT NULL,artist TEXT NOT NULL,album TEXT NOT NULL,duration_ms INTEGER NOT NULL,content_uri TEXT NOT NULL,data_path TEXT NOT NULL,album_id INTEGER NOT NULL,album_art_uri TEXT NOT NULL,codec TEXT NOT NULL DEFAULT '',bitrate_kbps INTEGER NOT NULL DEFAULT 0,sample_rate_hz INTEGER NOT NULL DEFAULT 0,bits_per_sample INTEGER NOT NULL DEFAULT 0,channel_count INTEGER NOT NULL DEFAULT 0,replay_gain_track_db REAL NOT NULL DEFAULT 0,replay_gain_album_db REAL NOT NULL DEFAULT 0,updated_at INTEGER NOT NULL);
CREATE TABLE favorites (track_id INTEGER PRIMARY KEY,created_at INTEGER NOT NULL);
CREATE TABLE play_history (track_id INTEGER PRIMARY KEY,played_at INTEGER NOT NULL,play_count INTEGER NOT NULL DEFAULT 1);
CREATE TABLE play_events (id INTEGER PRIMARY KEY AUTOINCREMENT,track_id INTEGER NOT NULL,played_at INTEGER NOT NULL);
CREATE TABLE playlists (id INTEGER PRIMARY KEY AUTOINCREMENT,name TEXT NOT NULL UNIQUE,created_at INTEGER NOT NULL,updated_at INTEGER NOT NULL);
CREATE TABLE playlist_tracks (playlist_id INTEGER NOT NULL,track_id INTEGER NOT NULL,position INTEGER NOT NULL,added_at INTEGER NOT NULL,PRIMARY KEY (playlist_id, track_id));
CREATE TABLE settings (`key` TEXT NOT NULL PRIMARY KEY,value TEXT NOT NULL);
CREATE TABLE remote_sources (id INTEGER PRIMARY KEY AUTOINCREMENT,type TEXT NOT NULL,name TEXT NOT NULL,base_url TEXT NOT NULL,username TEXT NOT NULL DEFAULT '',password TEXT NOT NULL DEFAULT '',root_path TEXT NOT NULL DEFAULT '/',last_status TEXT NOT NULL DEFAULT '',updated_at INTEGER NOT NULL);
CREATE TABLE playback_queue (position INTEGER PRIMARY KEY,track_id INTEGER NOT NULL,title TEXT NOT NULL DEFAULT '',artist TEXT NOT NULL DEFAULT '',album TEXT NOT NULL DEFAULT '',duration_ms INTEGER NOT NULL DEFAULT 0,content_uri TEXT NOT NULL DEFAULT '',data_path TEXT NOT NULL DEFAULT '',album_id INTEGER NOT NULL DEFAULT 0,album_art_uri TEXT NOT NULL DEFAULT '',codec TEXT NOT NULL DEFAULT '',bitrate_kbps INTEGER NOT NULL DEFAULT 0,sample_rate_hz INTEGER NOT NULL DEFAULT 0,bits_per_sample INTEGER NOT NULL DEFAULT 0,channel_count INTEGER NOT NULL DEFAULT 0,replay_gain_track_db REAL NOT NULL DEFAULT 0,replay_gain_album_db REAL NOT NULL DEFAULT 0);
CREATE TABLE streaming_track_matches (local_key TEXT NOT NULL,provider TEXT NOT NULL,provider_track_id TEXT NOT NULL,title TEXT NOT NULL DEFAULT '',artist TEXT NOT NULL DEFAULT '',data_path TEXT NOT NULL DEFAULT '',updated_at INTEGER NOT NULL,PRIMARY KEY (local_key, provider));
CREATE TABLE library_exclusions (source_key TEXT NOT NULL PRIMARY KEY,content_uri TEXT NOT NULL DEFAULT '',data_path TEXT NOT NULL DEFAULT '',created_at INTEGER NOT NULL);
CREATE INDEX idx_play_events_played_at ON play_events (played_at);
CREATE INDEX idx_play_events_track_time ON play_events (track_id, played_at);
CREATE INDEX idx_playlist_tracks_playlist ON playlist_tracks (playlist_id, position);
CREATE INDEX idx_remote_sources_type ON remote_sources (type, updated_at);
CREATE INDEX idx_playback_queue_track ON playback_queue (track_id);
CREATE INDEX idx_streaming_track_matches_provider_track ON streaming_track_matches (provider, provider_track_id);
CREATE INDEX idx_library_exclusions_created_at ON library_exclusions (created_at DESC);
CREATE INDEX idx_tracks_data_path ON tracks (data_path);
CREATE INDEX idx_tracks_artist ON tracks (artist);
CREATE INDEX idx_tracks_album ON tracks (album);
